function topicOf(row) {
  return String(row.topic || 'geral').toLowerCase();
}

function confidence(cluster) {
  const base = 55;
  const addBySources = Math.min(cluster.items.length * 8, 30);
  return Math.min(base + addBySources, 95);
}

// v2: Aggregate trend score from all cluster members
function aggregateTrendScore(cluster) {
  const scores = cluster.items.map(r => Number(r.trend_score) || 0);
  if (scores.length === 0) return 0;
  // Use max trend score + bonus for multiple high-trending sources
  const maxScore = Math.max(...scores);
  const highTrendCount = scores.filter(s => s >= 70).length;
  return Math.min(maxScore + (highTrendCount * 3), 100);
}

// v2: Calculate priority rank based on trend + confidence + volume
function calculatePriority(cluster) {
  const trend = cluster.trend_score || 0;
  const conf = cluster.confidence_score || 0;
  const vol = cluster.search_volume || 0;
  // Weighted composite: trend 40%, confidence 40%, volume 20%
  return Math.round((trend * 0.4) + (conf * 0.4) + Math.min(vol, 100) * 0.2);
}

let rows;
if (Array.isArray(items[0]?.json)) {
  rows = items[0].json;
} else {
  rows = items.map(i => i.json);
}
if (!rows || rows.length === 0) return [];

const clusters = new Map();
for (const row of rows) {
  const fp = row.duplicate_fingerprint || row.id;
  if (!clusters.has(fp)) {
    clusters.set(fp, {
      fingerprint: fp,
      topic: topicOf(row),
      primary_staging_id: row.id,
      source_count: 0,
      confidence_score: 0,
      trend_score: 0,
      search_volume: 0,
      priority_rank: 0,
      entities: [],
      staging_ids: [],
      items: []
    });
  }
  const cluster = clusters.get(fp);
  cluster.staging_ids.push(row.id);
  cluster.source_count += 1;
  cluster.items.push(row);
  // Track max search volume
  const sv = Number(row.search_volume) || 0;
  if (sv > cluster.search_volume) cluster.search_volume = sv;
}

const output = [];
for (const cluster of clusters.values()) {
  cluster.confidence_score = confidence(cluster);
  cluster.trend_score = aggregateTrendScore(cluster);
  cluster.priority_rank = calculatePriority(cluster);
  cluster.entities = [];
  delete cluster.items;
  output.push({ json: cluster });
}

// Sort by priority descending
output.sort((a, b) => (b.json.priority_rank || 0) - (a.json.priority_rank || 0));

return output;

const clusterData = $('Clusterize + Priority Rank').item.json;
const ids = Array.isArray(clusterData.staging_ids) ? clusterData.staging_ids : [];
const out = [];
for (const id of ids) {
  out.push({ json: { id: id, duplicate_fingerprint: clusterData.fingerprint } });
}
return out;
